export interface MapDot { x: number; y: number }

export const WORLD_DOTS: MapDot[] = DOTS.split(';').map((p) => {
  const [x, y] = p.split(',');
  return { x: Number(x), y: Number(y) };
});

// Project lat/lng onto the same 1000x500 canvas as the dots.
export function projectPoint(lat: number, lng: number): { x: number; y: number } {
  return {
    x: ((lng + 180) / 360) * 1000,
    y: ((90 - lat) / 180) * 500,
  };
}
